const input = $input.first().json;
const payload = input.body ?? input.payload ?? input;

return [{
  json: {
    ...input,
    payload,
    job_id: input.job_id ?? payload.job_id ?? payload?.job?.id,
    project_id: input.project_id ?? payload.project_id ?? payload?.project?.id,
    diagnosis_id: input.diagnosis_id ?? payload.diagnosis_id ?? payload?.diagnosis?.id,
    objective_id: input.objective_id ?? payload.objective_id ?? payload?.objective?.id,
    callback_url: input.callback_url ?? payload.callback_url,
    diagnosis_result: input.diagnosis_result ?? payload.diagnosis_result ?? payload?.diagnosisResult ?? {},
    objective_input: input.objective_input ?? payload.objective_input ?? payload?.objectiveInput ?? {}
  }
}];

const input = $input.first().json;

return [{
  json: {
    ...input,
    objective_result: {
      objective_type: 'mixed',
      smart_objective: 'Increase qualified organic traffic by improving the match between content clusters and search intent.',
      business_goal_alignment: 'Supports traffic growth and lead generation',
      input_metrics: input.objective_input,
      output_metrics: {
        target_traffic_growth: 30,
        target_conversion_growth: 15
      },
      outcome_metrics: {},
      baseline: input.objective_input?.seo_baseline ?? {},
      target: {
        monthly_organic_traffic: 10000,
        conversion_rate: 2.5
      },
      time_period: input.objective_input?.business_goal?.target_period ?? '6 months',
      achievability_score: 'moderate',
      achievability_percent: 68,
      risk_notes: ['Content production capacity should remain consistent'],
      reasoning: 'This objective follows from the current diagnosis and available baseline data.',
      next_step: 'Break the target into content, technical, and authority workstreams.',
      raw_llm_output: {
        source: 'n8n-template',
        note: 'Replace this node with your AI or rules-based analysis.'
      },
      model_used: 'n8n-template'
    }
  }
}];

const body = JSON.stringify($input.first().json);
const timestamp = Math.floor(Date.now() / 1000);
const secret = $env.APP_WEBHOOK_SECRET;
const crypto = require('crypto');
const signature = crypto.createHmac('sha256', secret).update(`${timestamp}.${body}`).digest('hex');

return [{
  json: {
    ...$input.first().json,
    n8n_timestamp: String(timestamp),
    n8n_signature: signature
  }
}];

